void checkSchedules() {
  if (currentMode != MODE_SCHEDULED) return;
  RtcDateTime now = Rtc.GetDateTime();
  if (!now.IsValid()) return;
  bool foundActiveSchedule = false;
  for (int i = 0; i < MAX_SCHEDULES; i++) {
    if (isScheduleActive(i)) {
      foundActiveSchedule = true;
      scheduleLightOn = true;
      if (!lightOn) {
        turnOnLight();
        Serial.printf("Расписание активно: %02d:%02d–%02d:%02d\n",
                      settings.schedules[i].startHour, settings.schedules[i].startMinute,
                      settings.schedules[i].endHour, settings.schedules[i].endMinute);
      }
      break;
    }
  }
  if (!foundActiveSchedule) {
    scheduleLightOn = false;
    if (lightOn) {
      turnOffLight();
      Serial.println("Вне периода расписания — свет выключен");
    }
  }
}

// === Ультразвук ===
float getDistance() {
  digitalWrite(TRIG_PIN, LOW);
  delayMicroseconds(2);
  digitalWrite(TRIG_PIN, HIGH);
  delayMicroseconds(10);
  digitalWrite(TRIG_PIN, LOW);
  long duration = pulseIn(ECHO_PIN, HIGH, 30000);
  if (duration == 0) return -1;
  return duration * 0.034 / 2.0;
}

// === EEPROM ===
void loadSettings() {
  EEPROM.begin(sizeof(Settings));
  EEPROM.get(0, settings);
  Settings temp = settings;
  temp.crc = 0;
  uint32_t crc = calculateCRC((uint8_t*)&temp, sizeof(Settings) - sizeof(uint32_t));
  if (settings.crc != crc) {
    settings.delayTime = 5000;
    settings.brightness = 200;
    for (int i = 0; i < MAX_SCHEDULES; i++) {
      settings.schedules[i].enabled = false;
      settings.schedules[i].active = false;
      settings.schedules[i].startHour = 0;
      settings.schedules[i].startMinute = 0;
      settings.schedules[i].endHour = 0;
      settings.schedules[i].endMinute = 0;
      settings.schedules[i].brightness = 200;
      for (int d = 0; d < 7; d++) settings.schedules[i].days[d] = true;
    }
    saveSettings();
    Serial.println("Настройки по умолчанию");
  }
  Serial.printf("Задержка: %lu мс, Яркость: %d\n", settings.delayTime, settings.brightness);
}

void saveSettings() {
  settings.crc = 0;
  settings.crc = calculateCRC((uint8_t*)&settings, sizeof(Settings) - sizeof(uint32_t));
  EEPROM.put(0, settings);
  EEPROM.commit();
  Serial.println("Настройки сохранены");
}

// === Управление светом (WS2812, фиолетовый) ===
void turnOnLight() {
  FastLED.setBrightness(settings.brightness);
  fill_solid(leds, NUM_LEDS, CRGB(200, 0, 200));

();
  lightOn = true;
  lightStartTime = millis();
  Serial.println("Включаем Уф-лампу");
}

void turnOffLight() {
  fill_solid(leds, NUM_LEDS, CRGB::Black);

();
  lightOn = false;
  Serial.println("Выключаем ленту");
}

// === RTC ===
void setRtcTime(int year, int month, int day, int hour, int minute, int second) {
  RtcDateTime dt(year, month, day, hour, minute, second);
  Rtc.SetDateTime(dt);
  Serial.println("Время успешно записано в RTC!");
}

