  server.send(200, "text/html", html);
}
void handleSetMode() {
  String mode = server.arg("mode");
  if (mode == "auto") currentMode = MODE_AUTO;
  else if (mode == "always_on") { currentMode = MODE_ALWAYS_ON; turnOnLight(); }
  else if (mode == "always_off") { currentMode = MODE_ALWAYS_OFF; turnOffLight(); }
  else if (mode == "manual") currentMode = MODE_MANUAL;
  else if (mode == "scheduled") { currentMode = MODE_SCHEDULED; checkSchedules(); }
  server.send(200, "text/plain", "OK");
}
void handleControl() {
  if (server.arg("state") == "on") { turnOnLight(); manualLightState = true; }
  else { turnOffLight(); manualLightState = false; }
  server.send(200, "text/plain", "OK");
}
void handleSaveSettings() {
  if (server.hasArg("delay") && server.hasArg("br")) {
    settings.delayTime = server.arg("delay").toInt();
    settings.brightness = server.arg("br").toInt();
    if (settings.delayTime < 1000) settings.delayTime = 1000;
    saveSettings();
    server.send(200, "text/plain", "OK");
  }
}
void handleResetTiming() {
  settings.delayTime = 5000;
  settings.brightness = 200;
