      json += "\"endHour\":" + String(settings.schedules[i].endHour) + ",";
      json += "\"endMinute\":" + String(settings.schedules[i].endMinute) + ",";
      json += "\"days\":[";
      for (int d = 0; d < 7; d++) {
        if (d > 0) json += ",";
        json += String(settings.schedules[i].days[d] ? "true" : "false");
      }
      json += "],";
      json += "\"brightness\":" + String(settings.schedules[i].brightness);
