void loop() {
  server.handleClient();

  // PIR
  bool pirMotion = digitalRead(PIR_PIN);
  static bool lastPir = false;
  if (pirMotion && !lastPir) addMotionEvent();
  lastPir = pirMotion;

  // Ультразвук
  static unsigned long lastUltrasonic = 0;
  if (millis() - lastUltrasonic > 200) {
    lastUltrasonic = millis();
    float dist = getDistance();
    if (dist > 0 && dist < 400) {
      if (lastDistance < 0) {
        lastDistance = dist;
        lastDistanceChange = millis();
      } else {
        float diff = abs(dist - lastDistance);
        if (diff > DIST_THRESHOLD_CM) {
          addMotionEvent();
          lastDistance = dist;
          lastDistanceChange = millis();
          distanceStable = false;
          if (lightOn) {
            turnOffLight();
            Serial.printf("Движение (ультразвук): %.1f → %.1f см\n", lastDistance - diff, dist);
          }
        }
      }
      if (!distanceStable && (millis() - lastDistanceChange >= DIST_STABLE_TIME)) {
        distanceStable = true;
        Serial.println("Ультразвук: стабильность 10 сек");
      }
    }
  }

  // Расписание
  if (millis() - lastScheduleCheck >= SCHEDULE_CHECK_INTERVAL) {
    lastScheduleCheck = millis();
    if (currentMode == MODE_SCHEDULED) checkSchedules();
  }

  // Основная логика
  bool noMotion = !pirMotion && distanceStable;
  if (currentMode == MODE_AUTO || (currentMode == MODE_SCHEDULED && scheduleLightOn)) {
    if (!noMotion) {
      if (lightOn) {
        turnOffLight();
        Serial.println("Движение — свет выключен");
      }
    } else if (!lightOn && (millis() - lastActivityTime >= settings.delayTime)) {
      turnOnLight();
      Serial.println("Нет движения 10+ сек — свет включён");
    }
  } else if (currentMode == MODE_ALWAYS_ON && !lightOn) turnOnLight();
  else if (currentMode == MODE_ALWAYS_OFF && lightOn) turnOffLight();
  else if (currentMode == MODE_SCHEDULED && !scheduleLightOn && lightOn) turnOffLight();

  delay(10);
}

